css:
color-scheme: dark;
  --app-bg: #050508;
  --app-surface: rgba(255, 255, 255, 0.03);
  --app-surface-hover: rgba(255, 255, 255, 0.05);
  --app-border: rgba(255, 255, 255, 0.07);
  --app-border-strong: rgba(255, 255, 255, 0.12);
  --app-text: #f2f4f8;
  --app-text-muted: #7d8494;
  --app-accent: #7eb4ff;
  --app-accent-soft: rgba(126, 180, 255, 0.14);
  --app-accent-border: rgba(126, 180, 255, 0.28);
  --app-accent-nav: rgba(126, 180, 255, 0.1);
  --app-elevated: #0c0c12;
  --app-glow-1: rgba(55, 145, 255, 0.14);
  --app-glow-2: rgba(55, 145, 255, 0.14);
  --app-card-shadow: 0 20px 40px rgba(0, 0, 0, 0.55), inset 0 1px 0 rgba(255, 255, 255, 0.08), inset 0 -1px 0 rgba(0, 0, 0, 0.45);
  --app-sidebar-bg: radial-gradient(circle at 12% -2%, var(--app-glow-1), transparent 38%), radial-gradient(circle at 94% 102%, var(--app-glow-2), transparent 36%), var(--app-bg);
  --app-shell-bg: var(--app-sidebar-bg);
  --media-snake-1: rgba(70, 120, 220, 0.14);
  --media-snake-2: rgba(110, 170, 255, 0.55);
  --media-snake-3: rgba(180, 210, 255, 0.95);
  --media-snake-4: rgba(90, 150, 255, 0.7);
  --bg-primary: var(--app-bg);
  --bg-secondary: var(--app-elevated);
  --bg-elevated: #101018;
  --bg-glass: rgba(10, 10, 16, 0.88);
  --text-primary: var(--app-text);
  --text-secondary: var(--app-text-muted);
  --text-tertiary: rgba(125, 132, 148, 0.72);
  --accent: var(--app-accent);
  --accent-blue: var(--app-accent);
  --focus-glow: rgba(126, 180, 255, 0.24);
